/****** Fuentes ******/
INSERT [ManV2].[Fuentes] ([fueClave], [fueDescrip], [fueDescripIng]) VALUES (191, N'Instituto Nacional de Estadística y Geografía (INEGI) y Secretaría del Trabajo y Previsión Social (STPS).¬1995-2004: Encuesta Nacional de Empleo (ENE), con proyecciones de población basadas en el Conteo de Población y Vivienda 2005.¬A partir de 2005: Encuesta Nacional de Ocupación y Empleo (ENOE), con proyecciones de población basadas en el Censo de Población y Vivienda 2010.', N'Instituto Nacional de Estadística y Geografía (INEGI) and Secretaría del Trabajo y Previsión Social (STPS).¬1995-2004: Encuesta Nacional de Empleo (ENE) with population projections based on the Conteo de Población y Vivienda 2005.¬From 2005: Encuesta Nacional de Ocupación y Empleo (ENOE), with population projections based on the Censo de Población y Vivienda 2010.')

